// Generated by GitHub Copilot
import '@testing-library/jest-dom/vitest';
import { cleanup, render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';
import ConfirmDialog from './ConfirmDialog';

vi.mock('../context/useLanguage', () => ({
  default: () => ({
    t: (key) => {
      if (key === 'common.confirm') return 'Confirmar';
      if (key === 'common.cancel') return 'Cancelar';
      if (key === 'common.loading') return 'Procesando...';
      return key;
    },
  }),
}));

function renderDialog(props = {}) {
  const onConfirm = vi.fn();
  const onCancel = vi.fn();

  const utils = render(
    <>
      <button type="button">Boton previo</button>
      <ConfirmDialog
        open
        title="Eliminar producto"
        message="Esta accion no se puede deshacer"
        onConfirm={onConfirm}
        onCancel={onCancel}
        {...props}
      />
    </>
  );

  return { ...utils, onConfirm, onCancel };
}

describe('ConfirmDialog', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  afterEach(() => {
    cleanup();
  });

  it('focuses cancel button when opened and restores focus on close', async () => {
    const { rerender } = render(
      <>
        <button type="button">Boton previo</button>
        <ConfirmDialog
          open={false}
          title="Eliminar producto"
          message="Esta accion no se puede deshacer"
          onConfirm={vi.fn()}
          onCancel={vi.fn()}
        />
      </>
    );

    const previousButton = screen.getByRole('button', { name: 'Boton previo' });
    previousButton.focus();
    expect(previousButton).toHaveFocus();

    rerender(
      <>
        <button type="button">Boton previo</button>
        <ConfirmDialog
          open
          title="Eliminar producto"
          message="Esta accion no se puede deshacer"
          onConfirm={vi.fn()}
          onCancel={vi.fn()}
        />
      </>
    );

    const cancelButton = screen.getByRole('button', { name: 'Cancelar' });
    expect(cancelButton).toHaveFocus();

    rerender(
      <>
        <button type="button">Boton previo</button>
        <ConfirmDialog
          open={false}
          title="Eliminar producto"
          message="Esta accion no se puede deshacer"
          onConfirm={vi.fn()}
          onCancel={vi.fn()}
        />
      </>
    );

    expect(previousButton).toHaveFocus();
  });

  it('traps keyboard focus with Tab and Shift+Tab', async () => {
    const user = userEvent.setup();
    renderDialog();

    const cancelButton = screen.getByRole('button', { name: 'Cancelar' });
    const confirmButton = screen.getByRole('button', { name: 'Confirmar' });

    expect(cancelButton).toHaveFocus();

    await user.keyboard('{Shift>}{Tab}{/Shift}');
    expect(confirmButton).toHaveFocus();

    await user.keyboard('{Tab}');
    expect(cancelButton).toHaveFocus();
  });

  it('calls onCancel when Escape is pressed', async () => {
    const user = userEvent.setup();
    const { onCancel } = renderDialog();

    await user.keyboard('{Escape}');

    expect(onCancel).toHaveBeenCalledTimes(1);
  });

  it('uses alertdialog role for destructive confirmations', () => {
    renderDialog({ destructive: true });

    expect(screen.getByRole('alertdialog', { name: 'Eliminar producto' })).toBeInTheDocument();
  });
});
